    uploadEventFont: {
        parameters: {
            query?: never;
            header?: never;
            path: {
                event_id: string;
            };
            cookie?: never;
        };
        requestBody: {
            content: {
                "multipart/form-data": {
                    /**
                     * Format: binary
                     * @description The font file. Extension must be .woff2, .woff, .ttf, or .otf (case-insensitive, anything else is rejected); max size 5MB.
                     */
                    file: string;
                    /** @description Display name, e.g. "Roboto Bold". */
                    name: string;
                    /** @description CSS font-family value, e.g. "Roboto". */
                    family: string;
                    /** @description Defaults to "normal" server-side if omitted/empty. */
                    weight?: string;
                    /** @description Defaults to "normal" server-side if omitted/empty. */
                    style?: string;
                    /** @description Must be the literal string "true" (read via c.FormValue, not a form boolean) or the request is rejected with 400. */
                    license_accepted: string;
                };
            };
        };
        responses: {
            /** @description Font created (FontListItem shape). */
            201: {
                headers: {
                    [name: string]: unknown;
                };
                content: {
                    "application/json": components["schemas"]["FontListItem"];
                };
            };
            /** @description event_id is not a UUID (checked before ownership) — or, once ownership passes: license_accepted is not the literal string "true", name/family missing, an unrecognized file extension, or a file over 5MB. */
            400: {
                headers: {
                    [name: string]: unknown;
                };
                content: {
                    "application/json": components["schemas"]["Error"];
                };
            };
            /** @description tenant_suspended from the tenant gate. */
            403: {
                headers: {
                    [name: string]: unknown;
                };
                content: {
                    "application/json": components["schemas"]["Error"];
                };
            };
            /** @description Event does not exist, or belongs to a different tenant (requireEventOwnership). */
            404: {
                headers: {
                    [name: string]: unknown;
                };
                content: {
                    "application/json": components["schemas"]["Error"];
                };
            };
            /** @description A font with the same family/weight/style already exists for this event (Store.CreateFont's unique-constraint branch). */
            409: {
                headers: {
                    [name: string]: unknown;
                };
                content: {
                    "application/json": components["schemas"]["Error"];
                };
            };
            /** @description Store failure resolving event ownership, reading the uploaded file's contents, or Store.CreateFont itself failing ("Failed to save font"). */
            500: {
                headers: {
                    [name: string]: unknown;
                };
                content: {
                    "application/json": components["schemas"]["Error"];
                };
            };
        };
    };
    getEventFontCss: {
        parameters: {
            query?: never;
            header?: never;
            path: {
                event_id: string;
            };
            cookie?: never;
        };
        requestBody?: never;
        responses: {
            /** @description CSS built with fmt.Fprintf into a strings.Builder and sent via c.String, with Content-Type explicitly set to "text/css; charset=utf-8" beforehand (so Echo's default text/plain never applies). Body is "" with just the leading comment when the event has no fonts (not an error). Documented as `format: binary` — it is genuinely UTF-8 text, but text/css has no body decoder registered in the contract-test harness (openapi3filter only ships JSON-family, text/csv, and text/plain decoders), so `format: binary` routes decoding through the same raw-bytes path already used for the image/png responses elsewhere in this file, instead of failing with "unsupported content type". */
            200: {
                headers: {
                    [name: string]: unknown;
                };
                content: {
                    "text/css": string;
                };
            };
            /** @description event_id is not a UUID. */
            400: {
                headers: {
                    [name: string]: unknown;
                };
                content: {
                    "application/json": components["schemas"]["Error"];
                };
            };
            /** @description tenant_suspended from the tenant gate. */
            403: {
                headers: {
                    [name: string]: unknown;
                };
                content: {
                    "application/json": components["schemas"]["Error"];
                };
            };
            /** @description Event does not exist, or belongs to a different tenant (requireEventOwnership). */
            404: {
                headers: {
                    [name: string]: unknown;
                };
                content: {
                    "application/json": components["schemas"]["Error"];
                };
            };
            /** @description Store failure resolving event ownership ("Internal error"), or Store.GetFontsByEventID itself failing ("Failed to get fonts"). Both render as application/json Error bodies, NOT text/css, despite the 200 response using a different content type. */
            500: {
                headers: {
                    [name: string]: unknown;
                };
                content: {
                    "application/json": components["schemas"]["Error"];
                };
            };
        };
    };
